module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output wfull,
    output rempty,
    output [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

reg [WIDTH-1:0] ram [DEPTH-1:0];
wire [ADDR_WIDTH-1:0] waddr, raddr;

reg [ADDR_WIDTH:0] write_ptr, read_ptr;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        write_ptr <= 0;
    end else if (winc && !wfull) begin
        ram[write_ptr[ADDR_WIDTH-1:0]] <= wdata;
        write_ptr <= write_ptr + 1;
    end
end

assign waddr = write_ptr[ADDR_WIDTH-1:0];

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        read_ptr <= 0;
    end else if (rinc && !rempty) begin
        read_ptr <= read_ptr + 1;
    end
end

assign raddr = read_ptr[ADDR_WIDTH-1:0];

reg [ADDR_WIDTH:0] rptr_sync1, rptr_sync2;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        rptr_sync1 <= 0;
        rptr_sync2 <= 0;
    end else begin
        rptr_sync1 <= read_ptr;
        rptr_sync2 <= rptr_sync1;
    end
end

reg [ADDR_WIDTH:0] wptr_sync1, wptr_sync2;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        wptr_sync1 <= 0;
        wptr_sync2 <= 0;
    end else begin
        wptr_sync1 <= write_ptr;
        wptr_sync2 <= wptr_sync1;
    end
end

assign rempty = (write_ptr == read_ptr);
assign wfull = (write_ptr[ADDR_WIDTH-1:0] == read_ptr[ADDR_WIDTH-1:0]) && (write_ptr[ADDR_WIDTH] != read_ptr[ADDR_WIDTH]);

assign rdata = ram[raddr];

endmodule
